"use strict";(self.webpackChunksailpoint_developer_portal=self.webpackChunksailpoint_developer_portal||[]).push([["899573"],{637141(e,t,i){i.r(t),i.d(t,{assets:()=>l,contentTitle:()=>s,default:()=>h,frontMatter:()=>r,metadata:()=>o,toc:()=>c});var o=i(543785),a=i(474848),n=i(28453);let r={id:"ambassador-agreement",title:"Ambassador Program Agreement",description:"The legal agreement governing participation in the SailPoint Ambassador Program.",slug:"/ambassador-agreement",displayed_sidebar:"communityPoliciesSidebar",custom_edit_url:null,hide_table_of_contents:!0,last_update:{date:new Date("2026-06-17T00:00:00.000Z")}},s,l={},c=[{value:"1. Program basics",id:"1-program-basics",level:2},{value:"2. Program details and benefits",id:"2-program-details-and-benefits",level:2},{value:"3. Program changes",id:"3-program-changes",level:2},{value:"4. SailPoint materials",id:"4-sailpoint-materials",level:2},{value:"4.1 Test materials",id:"41-test-materials",level:3},{value:"4.2 Test materials use restrictions",id:"42-test-materials-use-restrictions",level:3},{value:"5. SailPoint trademark and brand guidelines",id:"5-sailpoint-trademark-and-brand-guidelines",level:2},{value:"6. Confidential information",id:"6-confidential-information",level:2},{value:"7. Intellectual property",id:"7-intellectual-property",level:2},{value:"8. Compliance; additional restrictions",id:"8-compliance-additional-restrictions",level:2},{value:"9. Your materials",id:"9-your-materials",level:2},{value:"10. Term and termination",id:"10-term-and-termination",level:2},{value:"11. Non-exclusivity",id:"11-non-exclusivity",level:2},{value:"12. Indemnification",id:"12-indemnification",level:2},{value:"13. Disclaimer; liability limitation",id:"13-disclaimer-liability-limitation",level:2},{value:"14. Export compliance",id:"14-export-compliance",level:2},{value:"15. Miscellaneous",id:"15-miscellaneous",level:2}];function d(e){let t={a:"a",em:"em",h2:"h2",h3:"h3",hr:"hr",p:"p",strong:"strong",...(0,n.R)(),...e.components};return(0,a.jsxs)(a.Fragment,{children:[(0,a.jsx)("div",{class:"community-policy-page",hidden:!0,"aria-hidden":"true"}),"\n",(0,a.jsx)(t.p,{children:(0,a.jsx)(t.em,{children:"Last Updated June 17, 2026"})}),"\n",(0,a.jsx)(t.p,{children:'This Ambassador Program Agreement (the "Agreement") is a legal contract between the individual who accepts these terms ("Ambassador," "you" and "your") and SailPoint Technologies, Inc. (together with its affiliates, "SailPoint," "we" or "our"). Your participation in the Ambassador Program (the "Program") is subject to the terms of this Agreement. By clicking on the "I accept" button, or by participating in the Program, you agree to be bound by this Agreement. Please carefully read this Agreement. If you do not agree to the terms of this Agreement, do not click "I accept" or participate in the Program.'}),"\n",(0,a.jsx)(t.hr,{}),"\n",(0,a.jsx)(t.h2,{id:"1-program-basics",children:"1. Program basics"}),"\n",(0,a.jsx)(t.p,{children:"The Program is designed to give you the opportunity to participate in our developer community and deepen your familiarity with SailPoint's identity security products and services (\"SailPoint Services\"). To participate in the Program, you must be at least the age of majority in the country you live in (usually 18 years), and by entering into this Agreement you certify to SailPoint that you are at least the age of majority where you live. Because we may share confidential information about SailPoint's product features and plans with Program members, we do not permit employees of our competitors to participate in the Program. You hereby certify that you are either an employee or authorized representative of a current or prospective customer or partner of SailPoint. If you use any SailPoint community, support and engagement tools, such as the SailPoint Developer Community, Compass website; support portal; Identity University; Ideas portal, or any other SailPoint portal, product or tool that links to or incorporates additional terms, you agree to comply with all applicable terms for such tools. If there is a conflict between this Agreement and the terms in the prior sentence, the terms of this Agreement shall control with respect to all matters related to your participation in the Program."}),"\n",(0,a.jsx)(t.hr,{}),"\n",(0,a.jsx)(t.h2,{id:"2-program-details-and-benefits",children:"2. Program details and benefits"}),"\n",(0,a.jsxs)(t.p,{children:['Program members may receive certain benefits from SailPoint that are available only to Program members and not generally to other SailPoint customers and users ("SailPoint Customers"). Additional details relating to the Program such as benefits and membership requirements (including but not limited to the calculation and retention of membership points) can be located at the Developer Community website, available at ',(0,a.jsx)(t.a,{href:"https://developer.sailpoint.com/ambassadors/",children:"developer.sailpoint.com/ambassadors"}),' ("Program Guide"), hereby incorporated by reference as part of the Agreement. In accordance with the Program Guide, your Program benefits and perks may vary depending on which Program membership tier you qualify for.']}),"\n",(0,a.jsx)(t.hr,{}),"\n",(0,a.jsx)(t.h2,{id:"3-program-changes",children:"3. Program changes"}),"\n",(0,a.jsx)(t.p,{children:"You acknowledge that SailPoint may modify the Program or Agreement terms (including the Program Guide) from time to time. In doing so, SailPoint may provide advance notice of any updates and/or general communications with you about the Program via its regular communication channels with Program members, including to email addresses you have provided to SailPoint in connection with the Program; we will endeavor to provide at least fourteen (14) day's notice of any material changes or modifications related to the Program membership benefits, including calculation of Program points. By continuing to participate in the Program, you agree that you accept all of our modifications to this Agreement; in the case of changes or modifications to Program membership benefits, your continued participation after the fourteen (14) days' notice period constitutes acceptance of such changes. If you do not agree to changes to the Agreement terms (including the Program Guide), you must stop participating in the Program immediately."}),"\n",(0,a.jsx)(t.hr,{}),"\n",(0,a.jsx)(t.h2,{id:"4-sailpoint-materials",children:"4. SailPoint materials"}),"\n",(0,a.jsx)(t.p,{children:'As part of the Program, SailPoint may make available to you promotional materials, training documentation, Test Materials (defined below) and other materials related to the SailPoint Service (collectively and individually, the "SailPoint Materials"). Subject to your compliance with the Agreement terms, SailPoint grants you, during the term of this Agreement, a personal, limited, revocable, non-exclusive, non-transferable right to use the SailPoint Materials worldwide, for the sole and exclusive purpose of your personal enjoyment and participation in the Program. Please note that any violation or breach of this Section 4 may result in your prompt removal from the Program.'}),"\n",(0,a.jsx)(t.h3,{id:"41-test-materials",children:"4.1 Test materials"}),"\n",(0,a.jsxs)(t.p,{children:['As set forth in the Program Guide, SailPoint may make available to you a preproduction or sandbox instance of the SailPoint Service(s) ("Test Materials"). Subject to your compliance with the Agreement terms, and for the period you remain eligible to receive access under the Program Guide, SailPoint grants you a personal, limited, revocable, non-exclusive, non-transferrable, non-sublicensable right to access and use the Test Materials on a non-production basis, solely for internally evaluating and testing the SailPoint Service(s), in accordance with any applicable documentation provided by SailPoint (if any). To receive and use Test Materials, the email registered with your Developer Community account must be under an existing or prospective SailPoint customer or partner email domain; access to Test Materials through personal email or non-customer or partner emails will be denied. To update your Developer Community account email, request an email address change at ',(0,a.jsx)(t.a,{href:"mailto:login-help@sailpoint.com",children:"login-help@sailpoint.com"}),". You represent and warrant that you shall not grant administrative rights or log-in credentials to the Test Materials to any person other than yourself, and you will maintain strong passwords to all accounts. You shall be solely responsible for all activities conducted through your account and maintain security and confidentiality of your account. You shall notify SailPoint promptly of any such unauthorized access or use. SailPoint does not provide support, warranties, service level commitments, or indemnification for the Test Materials. You are solely responsible for maintaining a back-up of any data that you submit to the Test Materials. Access to the Test Materials may be terminated or suspended at any time in SailPoint's discretion, including after extended periods of non-use, and any data provided through such Test Materials prior to such termination or suspension may not be capable of being transferred or retained by SailPoint for use or access by you."]}),"\n",(0,a.jsx)(t.h3,{id:"42-test-materials-use-restrictions",children:"4.2 Test materials use restrictions"}),"\n",(0,a.jsx)(t.p,{children:"You shall not, and shall not permit others to:"}),"\n",(0,a.jsx)(t.p,{children:"a. Access the Test Materials or any applicable documentation, or SailPoint's confidential information to develop a product or service in competition with SailPoint's products or services;"}),"\n",(0,a.jsx)(t.p,{children:"b. Rent, sublicense, resell, assign, distribute, time share or otherwise commercially exploit the Test Materials;"}),"\n",(0,a.jsx)(t.p,{children:"c. Store in the Test Materials any production or confidential information, personal or sensitive data, key material or certificates of any kind;"}),"\n",(0,a.jsx)(t.p,{children:"d. Use the Test Materials to (or submit, upload or store in the Test Materials any content or data that) violate any applicable laws, any third-party intellectual property rights, or an individual's right of privacy or publicity;"}),"\n",(0,a.jsx)(t.p,{children:"e. Use the Test Materials to create, use, send, store, or run viruses, bots, worms, or similar harmful material;"}),"\n",(0,a.jsx)(t.p,{children:"f. Overload the capacity of the Test Materials or the system or network for such Test Materials or cause significant slowdown or burden to the same. Prohibited activities include but are not limited to load testing, stress testing, large source aggregations or bulk API operations;"}),"\n",(0,a.jsx)(t.p,{children:"g. Allow administrative accounts or other account credentials to be shared or used by more than one individual, or by any individual other than yourself;"}),"\n",(0,a.jsx)(t.p,{children:"h. Reverse engineer, copy, modify, adapt, or hack the Test Materials; or"}),"\n",(0,a.jsx)(t.p,{children:"i. Perform penetration testing or other benchmarking on the Test Materials."}),"\n",(0,a.jsx)(t.hr,{}),"\n",(0,a.jsx)(t.h2,{id:"5-sailpoint-trademark-and-brand-guidelines",children:"5. SailPoint trademark and brand guidelines"}),"\n",(0,a.jsxs)(t.p,{children:["As a condition of your participation in the Program, you agree to comply with the requirements set forth at ",(0,a.jsx)(t.a,{href:"https://brand.sailpoint.com/844e6c661/p/9864fd-sailpoint-brand-center",children:"SailPoint Brand Center"}),', as updated from time to time by SailPoint, whenever you use the SailPoint name, logos, artwork, or other brand features ("SailPoint Brand Assets"). If you are eligible to use any Program-specific logos or marks in accordance with the eligibility standards specified by SailPoint (such as when using the contents in your custom social share package), you are permitted to use such logos or marks only in accordance with the terms of this Agreement and the SailPoint Brand Center requirements. Failure to comply with the terms of this Section may result in immediate suspension or termination of your participation in the Program. Notwithstanding anything else, you shall not use the "SailPoint" name, any variation or similar name thereof in your username or display name on any SailPoint Developer Community platform.']}),"\n",(0,a.jsx)(t.hr,{}),"\n",(0,a.jsx)(t.h2,{id:"6-confidential-information",children:"6. Confidential information"}),"\n",(0,a.jsx)(t.p,{children:"All information provided to you by SailPoint that is not generally known or available to the public, that concerns SailPoint's business, technology, pricing, employees, customers, prospective customers, or financial affairs, including, without limitation, product roadmap information, other confidential plans for the SailPoint Service, and information which is identified by SailPoint as confidential or which a reasonable person would deem to be confidential under the circumstances (collectively, \"Confidential Information\") is and shall be SailPoint's exclusive property. You shall protect the Confidential Information from disclosure and you shall not disclose any Confidential Information to any person or entity without prior written approval by an officer of SailPoint, either during or after the term of this Agreement. Except with SailPoint's express prior written consent, or as required by law, you shall not use any Confidential Information except for the purpose of participating in the Program. You must cease using, return to SailPoint, and destroy all copies and extracts of all Confidential Information (including electronic files), immediately upon receipt of a request by SailPoint, and you must promptly confirm in writing that you have done so. If you become legally compelled to disclose any Confidential Information, you shall, if lawfully permitted to do so, immediately provide SailPoint with written notice and reasonable cooperation so that SailPoint may seek a protective order or other appropriate remedy to protect its interest in the Confidential Information. If you disclose or use (or threaten to disclose or use) any Confidential Information in breach of this Section 6, SailPoint shall have the right, in addition to any other remedies available to it, to seek injunctive relief to enjoin such acts."}),"\n",(0,a.jsxs)(t.p,{children:[(0,a.jsx)(t.strong,{children:"PLEASE READ THE FOLLOWING CAREFULLY:"})," Without limiting the foregoing: (a) if SailPoint provides you with or you otherwise have access to information about any SailPoint Customer(s), including without limitation any contact information or statistical information about such SailPoint Customer's use of the SailPoint Service, you shall use such information solely to assist such SailPoint Customer to optimize and enhance its use of the SailPoint Service; and (b) if SailPoint provides you with product roadmap information or other plans for the SailPoint Service or any other inventions or trade secrets, you shall use such information solely for your (or, if you are employed by a SailPoint Customer, the SailPoint Customer's) own internal planning purposes and you shall not disclose the information to anyone."]}),"\n",(0,a.jsx)(t.hr,{}),"\n",(0,a.jsx)(t.h2,{id:"7-intellectual-property",children:"7. Intellectual property"}),"\n",(0,a.jsx)(t.p,{children:'Except for the limited rights specifically granted to you in this Agreement, SailPoint reserves all right, title and interest, including, without limitation, all intellectual property rights, in and to the SailPoint Service, the SailPoint Materials, and SailPoint Brand Assets. You agree that this Agreement in no way provides any express or implied license to use or otherwise exploit the SailPoint Service, the SailPoint Materials, or the SailPoint Brand Assets, except as specifically set forth herein. Further, all use of the SailPoint Materials and SailPoint Brand Assets, including all goodwill therein, shall inure to the benefit of SailPoint. If you provide any suggestions, enhancement requests, feedback, recommendations or other information relating to any current or future SailPoint products or services or the SailPoint Materials ("Feedback"), you hereby grant SailPoint an irrevocable, perpetual, nonexclusive, worldwide, transferable, sub-licensable, royalty-free, fully paid up right and license to disclose, use and incorporate such Feedback in order to develop, improve, use, create, commercialize, or exploit any SailPoint products or services, without any compensation to you and without any obligation to provide any accounting or other reporting to you.'}),"\n",(0,a.jsx)(t.hr,{}),"\n",(0,a.jsx)(t.h2,{id:"8-compliance-additional-restrictions",children:"8. Compliance; additional restrictions"}),"\n",(0,a.jsx)(t.p,{children:"You agree to comply with all applicable laws and regulations in participating in the Program. You represent and warrant that you shall not: (a) make any inconsistent, false or misleading representations with respect to SailPoint, the SailPoint Service, or the SailPoint Materials; (b) hold yourself out as the agent of SailPoint under this Program, or make any representation, warranty or promise for or on behalf of SailPoint, or otherwise attempt to obligate SailPoint in any manner inconsistent with your other agreement(s) with SailPoint; or (c) engage in any deceptive, misleading, or unethical practices that are or might be detrimental to SailPoint or SailPoint Customers or damage SailPoint's reputation. You acknowledge that you have no authority to execute contracts on SailPoint's behalf, or to sell or resell subscriptions, seats, or upgrades to the SailPoint Service under this Program. SailPoint's obligations to SailPoint Customers are set forth in SailPoint's other agreements between SailPoint and such SailPoint Customers, and to the extent you are an employee of such SailPoint Customer, you are additionally bound to those terms. You are legally responsible for any person acting for you or on your behalf. You shall not, at any time during the term of the Program and thereafter, make statements or representations or otherwise communicate, directly or indirectly, in writing, orally, or otherwise that may disparage SailPoint or its respective officers, directors, employees or advisors."}),"\n",(0,a.jsx)(t.hr,{}),"\n",(0,a.jsx)(t.h2,{id:"9-your-materials",children:"9. Your materials"}),"\n",(0,a.jsx)(t.p,{children:'You are not required to maintain a website or other third-party materials to participate in the Program. However, if you elect in your own discretion to maintain a website or other third-party materials (collectively, "Your Materials") in connection with your participation in the Program, you are solely responsible for the development, operation, and maintenance of, and all costs associated with, Your Materials, and for the accuracy, timeliness and appropriateness of all content posted on the same. SailPoint disclaims all liability for these matters. You agree that Your Materials shall not engage in any of the unsuitable activities listed in the Agreement terms and you understand and agree that SailPoint may, in its sole discretion, request that you correct or retract Your Materials, or terminate you from the Program for any violations of the Agreement terms.'}),"\n",(0,a.jsx)(t.hr,{}),"\n",(0,a.jsx)(t.h2,{id:"10-term-and-termination",children:"10. Term and termination"}),"\n",(0,a.jsxs)(t.p,{children:['This Agreement shall commence on the date you click "I accept," or the date you begin to participate in the Program, whichever is earliest and continue in effect until terminated by either party. Either party may terminate this Agreement at any time. If you choose to do so, please send an email to ',(0,a.jsx)(t.a,{href:"mailto:developer-relations@sailpoint.com",children:"developer-relations@sailpoint.com"}),'. Upon termination, all rights and licenses granted to you under the Program and this Agreement shall immediately terminate and you must (a) remove all references to your participation in the Program from any website, publicly available advertising or other media; (b) cease use of, return or destroy all SailPoint Materials in your possession; and (c) otherwise cease from participating in the Program and from making any representation that you are still part of the Program. SailPoint may terminate or suspend your access to all or any part of the Program (or any SailPoint Materials) at any time, upon notice and without liability. For example, SailPoint may revoke your right to use any Program-specific logos or other identifiers you may have been eligible to use (such as "SailPoint Ambassador" badge or icons) at its sole discretion. Notwithstanding any termination or expiration of this Agreement, the terms set forth in Sections 6-15 shall survive and continue in effect.']}),"\n",(0,a.jsx)(t.hr,{}),"\n",(0,a.jsx)(t.h2,{id:"11-non-exclusivity",children:"11. Non-exclusivity"}),"\n",(0,a.jsx)(t.p,{children:"The rights granted by SailPoint to you in connection with this Agreement are non-exclusive. Except as expressly provided in this Agreement, nothing herein shall limit or otherwise impair either party's freedom to conduct its business. Without limiting the foregoing, you acknowledge and agree that SailPoint may offer products and services that compete with products and services you offer."}),"\n",(0,a.jsx)(t.hr,{}),"\n",(0,a.jsx)(t.h2,{id:"12-indemnification",children:"12. Indemnification"}),"\n",(0,a.jsx)(t.p,{children:"You agree to indemnify, defend, and hold SailPoint and its respective officers, directors, employees, members, shareholders, or representatives harmless from and against any claim or demand, including without limitation, reasonable attorneys' fees, made by any third party in connection with or arising out of your participation in the program or your violation of the terms of this Agreement. We reserve the right, at our own expense, to assume the exclusive defense and control of such disputes, and in any event you shall cooperate with SailPoint in asserting any available defenses."}),"\n",(0,a.jsx)(t.hr,{}),"\n",(0,a.jsx)(t.h2,{id:"13-disclaimer-liability-limitation",children:"13. Disclaimer; liability limitation"}),"\n",(0,a.jsx)(t.p,{children:'TO THE MAXIMUM EXTENT PERMITTED BY APPLICABLE LAW, THE PROGRAM, SAILPOINT MATERIALS AND SAILPOINT BRAND ASSETS ARE PROVIDED "AS IS" WITHOUT WARRANTY, REPRESENTATION, CONDITION, OR GUARANTEE OF ANY KIND, EITHER EXPRESSED OR IMPLIED, INCLUDING BUT NOT LIMITED TO ANY IMPLIED WARRANTIES, REPRESENTATIONS, CONDITIONS OR GUARANTEES OF QUALITY, MERCHANTABILITY, FITNESS FOR A PARTICULAR PURPOSE, OR NON-INFRINGEMENT. YOU ACKNOWLEDGE THAT YOU HAVE NO EXPECTATION AND HAVE NOT RECEIVED ANY ASSURANCE THAT ANY INVESTMENT IN THE PROGRAM SHALL BE RECOVERED OR RECOUPED OR THAT YOU SHALL OBTAIN ANY PROFIT AS A RESULT OF PARTICIPATING IN THE PROGRAM. SAILPOINT SHALL NOT BE LIABLE FOR ANY ACCESS TO, USE OF OR RELIANCE ON THE PROGRAM, THE SAILPOINT MATERIALS OR THE SAILPOINT BRAND ASSETS BY YOU OR ANYONE ELSE, OR FOR ANY TRANSACTIONS, COMMUNICATIONS, INTERACTIONS, DISPUTES OR RELATIONS BETWEEN YOU AND ANY OTHER PERSON OR ORGANIZATION ARISING OUT OF OR RELATED TO SAILPOINT OR THE PROGRAM. YOUR PARTICIPATION IN THE PROGRAM IS AT YOUR OWN RISK.'}),"\n",(0,a.jsx)(t.p,{children:"IN NO EVENT SHALL SAILPOINT OR ITS LICENSORS, VENDORS, OR ANY OF THEIR RESPECTIVE DIRECTORS, OFFICERS, EMPLOYEES, AGENTS, OR OTHER REPRESENTATIVES BE LIABLE TO YOU OR ANY OTHER PERSON OR ENTITY FOR ANY INDIRECT, SPECIAL, INCIDENTAL, CONSEQUENTIAL, OR PUNITIVE DAMAGES (INCLUDING, BUT NOT LIMITED TO, DAMAGES FOR LOSS OF PROFITS, LOSS OF DATA, LOSS OF USE, OR COSTS OF OBTAINING SUBSTITUTE GOODS OR SERVICES), ARISING OUT OF OR IN CONNECTION WITH THIS AGREEMENT OR THE PROGRAM, SAILPOINT MATERIALS AND SAILPOINT BRAND ASSETS, WHETHER OR NOT SAILPOINT HAS BEEN ADVISED OF THE POSSIBILITY OF SUCH DAMAGES AND WHETHER BASED UPON WARRANTY, CONTRACT, TORT, STRICT LIABILITY, VIOLATION OF STATUTE, OR OTHERWISE. THIS EXCLUSION OF LIABILITY SHALL APPLY TO THE FULLEST EXTENT PERMITTED BY LAW. IN ANY EVENT, SAILPOINT'S AGGREGATE LIABILITY, AND THE AGGREGATE LIABILITY OF OUR LICENSORS AND VENDORS, TO YOU OR ANY THIRD PARTIES ARISING OUT OF OR RELATING TO THIS AGREEMENT IS LIMITED TO $100. THE FOREGOING LIMITATIONS SHALL APPLY EVEN IF A REMEDY FAILS OF ITS ESSENTIAL PURPOSE AND TO THE FULLEST EXTENT PERMITTED BY LAW."}),"\n",(0,a.jsx)(t.hr,{}),"\n",(0,a.jsx)(t.h2,{id:"14-export-compliance",children:"14. Export compliance"}),"\n",(0,a.jsx)(t.p,{children:"The Program and SailPoint Materials may be subject to export laws and regulations of the United States and other jurisdictions. You represent that you are not named on any U.S. government denied-party list. You shall not permit anyone to access or use any SailPoint Materials in a U.S.-embargoed country or region or in violation of any U.S. export law or regulation."}),"\n",(0,a.jsx)(t.hr,{}),"\n",(0,a.jsx)(t.h2,{id:"15-miscellaneous",children:"15. Miscellaneous"}),"\n",(0,a.jsx)(t.p,{children:"This Agreement (and all terms and conditions incorporated herein) constitutes the entire agreement between you and SailPoint with respect to its subject matter, and supersedes all other proposals, statements and agreements, including any previous agreement relating to the Program. A waiver or consent given by either party on any one occasion shall be effective only in that instance and shall not be construed as a bar or waiver of any right on any other occasion, including any other agreements you have with SailPoint. You agree that, except as otherwise expressly provided in this Agreement, there shall be no third-party beneficiaries to this Agreement. This Agreement and any rights or licenses granted hereunder to you are personal and may not be assigned or delegated by you. This Agreement and any rights or licenses granted hereunder, may be assigned or delegated by SailPoint without restriction. This Agreement may not be modified by an oral statement by a representative of SailPoint. We may deliver notice to you by e-mail, posting a notice on the SailPoint Developer Community website, or any other method we elect and such notice shall be effective on dispatch. Subject to Section 15, the parties agree that exclusive jurisdiction and venue of any action with respect to this Agreement shall be in a state or federal court located in Travis County, Texas, and each of the parties hereby submits to jurisdiction and venue of such courts for the purpose of any such action. If you are located outside the U.S., you acknowledge and agree that this Agreement is only being offered in English, and that if there is any translation of this Agreement, the English version shall govern. Should any provision of this Agreement, or any provision incorporated into this Agreement in the future, be or become invalid or unenforceable, the validity or enforceability of the other provisions of this Agreement shall not be affected thereby. The invalid or unenforceable provision shall be deemed to be substituted by a suitable and equitable provision that, to the extent legal permissible, comes as close as possible to the intent and purpose of the invalid or unenforceable provision. The section titles in this Agreement are for convenience and have no legal or contractual effect."})]})}function h(e={}){let{wrapper:t}={...(0,n.R)(),...e.components};return t?(0,a.jsx)(t,{...e,children:(0,a.jsx)(d,{...e})}):d(e)}},28453(e,t,i){i.d(t,{R:()=>r,x:()=>s});var o=i(296540);let a={},n=o.createContext(a);function r(e){let t=o.useContext(n);return o.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function s(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(a):e.components||a:r(e.components),o.createElement(n.Provider,{value:t},e.children)}},543785(e){e.exports=JSON.parse('{"id":"ambassador-agreement","title":"Ambassador Program Agreement","description":"The legal agreement governing participation in the SailPoint Ambassador Program.","source":"@site/docs/ambassador-agreement.md","sourceDirName":".","slug":"/ambassador-agreement","permalink":"/docs/ambassador-agreement","draft":false,"unlisted":false,"editUrl":null,"tags":[],"version":"current","frontMatter":{"id":"ambassador-agreement","title":"Ambassador Program Agreement","description":"The legal agreement governing participation in the SailPoint Ambassador Program.","slug":"/ambassador-agreement","displayed_sidebar":"communityPoliciesSidebar","custom_edit_url":null,"hide_table_of_contents":true,"last_update":{"date":"2026-06-17T00:00:00.000Z"}},"sidebar":"communityPoliciesSidebar","previous":{"title":"Ambassador Code of Conduct","permalink":"/docs/ambassador-code-of-conduct"}}')}}]);